diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index eb339282fdae..7b3fb3ae239f 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -19533,6 +19533,24 @@ BoUpSLP::BlockScheduling::tryScheduleBundle(ArrayRef<Value *> VL, BoUpSLP *SLP,
            !ReadyInsts.empty()) {
       ScheduleEntity *Picked = ReadyInsts.pop_back_val();
       assert(Picked->isReady() && "must be ready to schedule");
+
+      // If the picked entity is part of a cycle and still not ready, it means
+      // that it has cyclic dependencies. In this case we first schedule the
+      // dependencies and then the picked entity itself.
+      // TODO: This is a work-around that covers scheduling of instructions
+      // in a basic block. A better approach would be to have a global
+      // scheduling of all nodes in the graph.
+      if (Picked->isCycle() && !Picked->isReady()) {
+        for (Value *Op : Picked->getOperands()) {
+          if (auto *I = dyn_cast<Instruction>(Op)) {
+            if (ScheduleData *OpSD = getScheduleData(I)) {
+              if (isInSchedulingRegion(OpSD) && !OpSD->isScheduled())
+                schedule(OpSD, ReadyInsts);
+            }
+          }
+        }
+      }
+
       schedule(Picked, ReadyInsts);
       if (Picked == &Bundle)
         break;
